import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.buffer.com";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal000";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Buffer API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:buffer",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const bufferFirewall = {",
    '  name: "buffer",',
    '  description: "Buffer",',
    "  placeholders: {",
    `    BUFFER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.buffer.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.BUFFER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://api.bufferapp.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.BUFFER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Buffer firewall config...");
  const ts = generateTypeScript();
  writeOutput("buffer", ts, import.meta.dirname);
}
